from array import array

def main():
    arr = array('u', ['a', 'b', 'c', 'd'])

    for i in range(int(len(arr) / 2)):
        arr[i], arr[len(arr) - i - 1] = (arr[len(arr) - i - 1], arr[i])

    print('Output:', arr, end='\n' + '-' * 40)

if __name__ == "__main__":
    main()

